AGENTS = [{'key': 'random', 'display_name': 'Random', 'description': 'Picks a random legal action', 'architecture': 'A stateless baseline agent: on each turn it enumerates every legal action from the current position and samples one uniformly at random. There is no model, no search, and no learning — it exists purely as a lower bound for measuring the strength of every other agent and as a sanity-check opponent during training.', 'kind': 'inline', 'play_params': [], 'model_path': None, 'training_script': None, 'training_params': [], 'training_cli_map': {}, 'total_episodes_key': None, 'log_parser': None, 'config_file': None}, {'key': 'basic_minimax', 'display_name': 'Basic Minimax', 'description': 'Alpha-beta minimax with a fixed hand-crafted evaluation (no training required — reference template for a weightless agent)', 'architecture': 'Stripped-down alpha-beta minimax intended as a readable reference for any agent that does not need training. Search runs to a small fixed maximum depth under a per-move time budget, with simple alpha-beta pruning and no transposition table. The leaf evaluation is a fixed hand-crafted scoring function (not learned), so play strength comes entirely from search depth and the quality of that single eval — perfect as a template when prototyping a new agent that should compete without any weights.', 'kind': 'class', 'module': 'ai.classical.basic_minimax', 'class_name': 'BasicMinimaxAgent', 'play_kwargs': {'player': 1}, 'needs_player': True, 'play_params': [{'key': 'time_budget', 'label': 'Time budget (s)', 'type': 'number', 'default': 1.0, 'step': 0.1, 'min': 0.1, 'max': 30, 'tooltip': 'Per-move search time budget.'}, {'key': 'max_depth', 'label': 'Max depth', 'type': 'number', 'default': 2, 'step': 1, 'min': 1, 'max': 6, 'tooltip': 'Maximum alpha-beta search depth.'}], 'model_path': None, 'training_script': None, 'training_params': [], 'training_cli_map': {}, 'total_episodes_key': None, 'log_parser': None, 'config_file': None}, {'key': 'cnn_basic', 'display_name': 'Basic CNN', 'description': 'Tiny two-layer convolutional value network (reference template for a trainable agent)', 'architecture': 'A small convolutional value network operating directly on the 19×19 board. The position is encoded as an 8-channel tensor (own/opponent circle, accent, and special tiles, a growing-state plane, and a static valid-square mask). Two 3×3 convolutional layers with ReLU extract local spatial patterns, then a linear head with tanh outputs a scalar value in [-1, 1]. At play time the agent rolls every legal move forward one ply, runs the CNN on the resulting board, and picks the action whose successor scores highest.', 'kind': 'class', 'module': 'ai.rl.cnn_basic', 'class_name': 'CNNBasicAgent', 'play_kwargs': {'player': 1, 'load': True}, 'needs_player': True, 'play_params': [{'key': 'epsilon', 'label': 'Exploration (epsilon)', 'type': 'number', 'default': 0.0, 'step': 0.01, 'min': 0.0, 'max': 1.0, 'tooltip': 'Play-time exploration probability (0 = greedy).'}, {'key': 'device', 'label': 'Device', 'type': 'text', 'default': 'cpu', 'tooltip': 'cpu or cuda'}], 'model_path': 'ai/params/CNNBasic/cnn_basic.pt', 'training_script': 'ai/training/cnn_basic_training.py', 'training_params': [{'key': 'episodes', 'label': 'Episodes', 'type': 'number', 'default': 200, 'step': 50, 'min': 1, 'tooltip': 'Number of self-play training episodes'}, {'key': 'lr', 'label': 'Learning Rate', 'type': 'number', 'default': 0.001, 'step': 0.0001, 'min': 1e-05, 'max': 1, 'tooltip': 'Adam optimizer learning rate'}, {'key': 'epsilon', 'label': 'Start Epsilon', 'type': 'number', 'default': 0.5, 'step': 0.01, 'min': 0, 'max': 1, 'tooltip': 'Initial exploration rate'}, {'key': 'min_epsilon', 'label': 'Min Epsilon', 'type': 'number', 'default': 0.05, 'step': 0.01, 'min': 0, 'max': 1, 'tooltip': 'Floor for epsilon decay'}, {'key': 'decay', 'label': 'Epsilon Decay', 'type': 'number', 'default': 0.995, 'step': 0.001, 'min': 0, 'max': 1, 'tooltip': 'Multiply epsilon by this each episode'}, {'key': 'max_steps', 'label': 'Max Steps', 'type': 'number', 'default': 300, 'step': 50, 'min': 50, 'tooltip': 'Max turns per self-play game'}, {'key': 'batch_size', 'label': 'Batch Size', 'type': 'number', 'default': 32, 'step': 8, 'min': 1, 'tooltip': 'Minibatch size for the value-regression step'}, {'key': 'opponent', 'label': 'Opponent', 'type': 'text', 'default': 'self', 'tooltip': 'Training opponent (filled in after registry is built)'}, {'key': 'device', 'label': 'Device', 'type': 'text', 'default': 'cpu', 'tooltip': 'cpu or cuda'}, {'key': 'resume', 'label': 'Resume from checkpoint', 'type': 'checkbox', 'default': False, 'tooltip': 'Load existing weights and continue training'}], 'training_cli_map': {'episodes': '--n', 'lr': '--lr', 'epsilon': '--eps', 'min_epsilon': '--min_eps', 'decay': '--decay', 'max_steps': '--ms', 'batch_size': '--batch', 'opponent': '--opponent', 'device': '--device', 'resume': '--resume'}, 'total_episodes_key': 'episodes', 'log_parser': None, 'config_file': 'ai/params/CNNBasic/example_config.txt'}]

def _fill_opponent_tooltip(agent_key):
    """For agents with an `opponent` training param, set tooltip to `self` +
    every other registry key, so the UI hover-tip stays in sync with the
    registry."""
    entry = next((a for a in AGENTS if a['key'] == agent_key), None)
    if not entry:
        return
    others = [a['key'] for a in AGENTS if a['key'] != agent_key]
    options = ['self'] + others
    for tp in entry.get('training_params', []):
        if tp.get('key') in ('opponent', 'p2'):
            tp['tooltip'] = 'Training opponent: ' + ', '.join(options)
for _k in ('cnn_basic', 'nneu_basic'):
    _fill_opponent_tooltip(_k)
_BY_KEY = {a['key']: a for a in AGENTS}

def get_agent(key):
    return _BY_KEY.get(key.lower())

def all_agents():
    return AGENTS

def playable_agents():
    return AGENTS

def trainable_agents():
    return [a for a in AGENTS if a.get('training_script')]
